        }),
      ).resolves.toBe(
        formatStringTemplate(`3:Nor how it may concern my modesty,
        5:But I beseech your grace that I may know
        6:The worst that may befall me in this case,`),
      );
    });

    xit('One file, several matches, match entire lines flag', () => {
      return expect(
        spawnGrep({
          pattern: 'may',
